import 'package:cloud_firestore/cloud_firestore.dart';

Future<void> seedAllRestaurants() async {
  final col = FirebaseFirestore.instance.collection('restaurants');
  final existing = await col.limit(1).get();
  if (existing.docs.isNotEmpty) { print('Already seeded.'); return; }

  final batch = FirebaseFirestore.instance.batch();
  for (final r in _data()) { batch.set(col.doc(), r); }
  await batch.commit();
  print('✅ 12 restaurants seeded!');
}

